import{_ as a,o as p,c as t,j as e,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"镜像行者护甲—偏折水晶","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/2.改造与功法/改造/2.社交类/镜像行者/镜像行者护甲—偏折水晶.md","filePath":"4.资源分区/2.改造与功法/改造/2.社交类/镜像行者/镜像行者护甲—偏折水晶.md"}'),_={name:"4.资源分区/2.改造与功法/改造/2.社交类/镜像行者/镜像行者护甲—偏折水晶.md"};function o(d,r,l,b,i,c){return p(),t("div",null,[...r[0]||(r[0]=[e("h1",{id:"镜像行者护甲—偏折水晶",tabindex:"-1"},[n("镜像行者护甲—偏折水晶 "),e("a",{class:"header-anchor",href:"#镜像行者护甲—偏折水晶","aria-label":'Permalink to "镜像行者护甲—偏折水晶"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风029特别节愚人版")])])],-1),s('<h1 id="镜像行者护甲—偏折水晶-1" tabindex="-1">镜像行者护甲—偏折水晶 <a class="header-anchor" href="#镜像行者护甲—偏折水晶-1" aria-label="Permalink to &quot;镜像行者护甲—偏折水晶&quot;">​</a></h1><p>偏折水晶</p><p>你必须潜入分形树的每片叶脉，在黄金分割点的断裂处收集被遗忘的波函数。<br> 那些纠缠的光子正在虚数轴上跳华尔兹，而你的瞳孔里旋转着哥德尔不完备定理的莫比乌斯环。<br> 要小心黎曼猜想在双曲空间投射的阴影，它们会篡改你记忆晶格中的拓扑结构。</p><p>D+500<br> 这是一颗纯黑的水晶，你仅能通过从晶体边缘上反射的光芒来定位它。</p><p>【折光】<br> 当你兑换该等级后，倒影的遮蔽防御上升4点，并且现在其具有【全伤害吸收1】，<br> 镜像行者每在心智类属性上具有1点传奇属性，那么就为倒影提供1点抵威猛。</p><p>逐级提升</p><p>C+1000<br> 这是一块物质，其仅吸收光线，如同空间中的一块永存的黑暗。</p><p>【纯黑】<br> 必须用遍历环面的无理流切割超导能隙中的马约拉纳零模，直到阿贝尔规范场的尖啸在陈-西蒙斯理论中结晶为四维流形的痛觉神经。<br> 那些被离散对称性囚禁的斯格明子，正在量子反常的泥沼里重组为霍奇循环的骨骼标本。</p><p>当你兑换该等级后，倒影的遮蔽防御额外上升5点，并且额外获得【全伤害吸收1】，<br> 并且该兑换会为其提供基于遮蔽防御的【适应】和对攻击方生效的【劣化1】。</p><p>B+2000<br> 这是一个空洞，它被锚定在镜像行者的思维中，旁人无法观测，仅能看到其在现实中的倒影。</p><p>【不可视】<br> 当阿基米德支点开始在非标准分析的潮汐中锈蚀，你要在巴拿赫空间的孔隙里培育分数量子霍尔效应的菌落<br> 。每个朗道能级的褶皱都包裹着未被观测的贝尔基态，而你的突触正被拓扑序的弦网凝聚切割成不可区分的全同粒子。</p><p>当你兑换该等级后，倒影的遮蔽防御额外上升5点，并且额外获得【全伤害吸收1】，</p><p>上一级中获得的【劣化1】升级至【劣化2】，并且具有基于遮蔽防御的【坚韧】，</p><p>倒影同时免疫B级的胁迫、支配、思维控制效果。</p><p>【不可知】<br> 当微分同胚的幽灵开始蚕食规范不变的边界条件，你必须用非平衡态热力学的箭矢射穿遍历性假说的喉舌。<br> 那些在量子泡沫中沸腾的拓扑缺陷，此刻正以共形场论的语法重写延拓定理的遗嘱。每个不可测集的颤抖，都是代数在因子中分娩的熵爆。</p><p>倒影现在具有普通飞行能力，并且其基础移速提升60M。</p><p>并且，倒影免疫B级的解析、预知、读心效果。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',19)])])}const m=a(_,[["render",o]]);export{f as __pageData,m as default};
